import type { Metadata } from 'next';
import Link from 'next/link';
import { headers } from 'next/headers';

import { ViewAllPostsButton } from '@/app/components/view-all-posts-button';
import { getRecentPosts } from '@/app/lib/data';

export const metadata: Metadata = {
  title: 'Home',
  description: 'Welcome to my blog homepage',
  openGraph: {
    title: 'Home - My Blog',
  },
};

export default async function HomePage() {
  const [posts, requestHeaders] = await Promise.all([getRecentPosts(), headers()]);
  const userAgent = requestHeaders.get('user-agent') ?? '';
  const timestamp = new Date().toISOString();

  return (
    <div>
      <h1>Welcome to My Blog</h1>
      <p>Server-side rendered at: {timestamp}</p>
      <p>Your user agent: {userAgent}</p>

      <h2>Recent Posts</h2>
      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <Link href={`/blog/${post.id}`}>{post.title}</Link>
          </li>
        ))}
      </ul>

      <ViewAllPostsButton />
    </div>
  );
}

import type { Metadata } from 'next';
import Link from 'next/link';

import { ReadMoreButton } from '@/app/components/read-more-button';
import { getAllPosts } from '@/app/lib/data';

export const metadata: Metadata = {
  title: 'Blog',
  description: 'All blog posts',
};

export default async function BlogIndexPage() {
  const posts = await getAllPosts();

  return (
    <div>
      <h1>All Blog Posts</h1>

      <div className="posts-grid">
        {posts.map((post) => (
          <div key={post.id} className="post-card">
            <h2>
              <Link href={`/blog/${post.id}`}>{post.title}</Link>
            </h2>
            <p>{post.body?.substring(0, 100)}...</p>
            <ReadMoreButton postId={post.id} />
          </div>
        ))}
      </div>
    </div>
  );
}
